// 値が空 (null/undefined/'') かどうか。0 や false は有効値。
function _tutugaIsEmpty(v) {
  return v === null || v === undefined || v === '';
}

// セルに値を書き込む。空値は書き込まない (テンプレ初期値を温存)。
function _tutugaWriteCell(ws, row, col, value) {
  if (_tutugaIsEmpty(value)) return;
  ws.getCell(row, col).value = value;
}

// 注入済みグローバル定数を必要時に解決する (index.html 側に存在するはず)
function _tutugaConst(name, fallback) {
  if (typeof window !== 'undefined' && typeof window[name] !== 'undefined') return window[name];
  // GAS / Node 評価時のフォールバック
  try { return eval(name); } catch (e) { return fallback; }
}

// 共通: 日常水質シート (上段使用量 + 下段水質測定)
function _tutugaWriteWaterSheet(ws, allData) {
  var WATER_BLOCK_ROW   = _tutugaConst('WATER_BLOCK_ROW',   { 1:1, 2:53, 3:105, 4:157, 5:209 });
  var USAGE_DAY_COL     = _tutugaConst('USAGE_DAY_COL',     { mon:9, tue:10, wed:11, thu:12, fri:13, nextMon:14 });
  var MEASURE_DAY_COL   = _tutugaConst('MEASURE_DAY_COL',   { mon:10, tue:11, wed:12, thu:13, fri:14 });
  var USAGE_CELLS = ['mon','tue','wed','thu','fri','nextMon'];
  var DAYS5 = ['mon','tue','wed','thu','fri'];

  // 上段使用量 (per-week, 9 項目, 6 セル mon-fri+nextMon)
  for (var w = 1; w <= 5; w++) {
    var weekData = (allData.waterUsage && allData.waterUsage[w]) || null;
    if (!weekData) continue;
    var blockRow = WATER_BLOCK_ROW[w];
    if (!blockRow) continue;
    Object.keys(TUTUGA_USAGE_ROW_OFFSET).forEach(function(key) {
      var rowOff = TUTUGA_USAGE_ROW_OFFSET[key];
      var perDay = weekData[key];
      if (!perDay || typeof perDay !== 'object') return;
      USAGE_CELLS.forEach(function(dc) {
        _tutugaWriteCell(ws, blockRow + rowOff, USAGE_DAY_COL[dc], perDay[dc]);
      });
    });
  }

  // 下段水質測定 (per-day, 28 項目, 5 セル mon-fri)
  for (var w2 = 1; w2 <= 5; w2++) {
    var weekDays = (allData.waterMeasure && allData.waterMeasure[w2]) || null;
    if (!weekDays) continue;
    var blockRow2 = WATER_BLOCK_ROW[w2];
    if (!blockRow2) continue;
    DAYS5.forEach(function(dc) {
      var dayData = weekDays[dc];
      if (!dayData || typeof dayData !== 'object') return;
      Object.keys(TUTUGA_MEASURE_ROW_OFFSET).forEach(function(key) {
        var rowOff = TUTUGA_MEASURE_ROW_OFFSET[key];
        _tutugaWriteCell(ws, blockRow2 + rowOff, MEASURE_DAY_COL[dc], dayData[key]);
      });
    });
  }
}

// 機器運転時間シート
function _tutugaWriteEquipmentSheet(ws, allData) {
  var EQUIP_WEEK_START   = _tutugaConst('EQUIP_WEEK_START',   { 1:8, 2:46, 3:84, 4:122, 5:160 });
  var EQUIP_HOUR_DAY_COL = _tutugaConst('EQUIP_HOUR_DAY_COL', { mon:4, tue:5, wed:6, thu:7, fri:8 });
  var DAYS5 = ['mon','tue','wed','thu','fri'];

  for (var w = 1; w <= 5; w++) {
    var weekData = (allData.equipment && allData.equipment[w]) || null;
    if (!weekData) continue;
    var startRow = EQUIP_WEEK_START[w];
    if (!startRow) continue;
    TUTUGA_EQUIP_KEYS_ORDERED.forEach(function(key, idx) {
      var perDay = weekData[key];
      if (!perDay || typeof perDay !== 'object') return;
      var row = startRow + idx;
      DAYS5.forEach(function(dc) {
        _tutugaWriteCell(ws, row, EQUIP_HOUR_DAY_COL[dc], perDay[dc]);
      });
    });
  }
}

// 日常電気設備シート (sub1/2/3 を 1 シートに 5 週分書き込み)
function _tutugaWriteElectricalSheet(ws, allData) {
  var WEEK_OFFSETS_ELEC = _tutugaConst('WEEK_OFFSETS_ELEC', {
    sub1: [0, 103, 203, 303, 403],
    sub2: [0, 101, 201, 301, 401],
    sub3: [0, 100, 200, 300, 400]
  });
  var ELEC_DAY_COL = _tutugaConst('ELEC_DAY_COL', { mon:7, tue:8, wed:9, thu:10, fri:11 });
  var DAYS5 = ['mon','tue','wed','thu','fri'];
  var subMaps = [
    { offsets: WEEK_OFFSETS_ELEC.sub1, rowMap: TUTUGA_ELEC1_ROW_W1 },
    { offsets: WEEK_OFFSETS_ELEC.sub2, rowMap: TUTUGA_ELEC2_ROW_W1 },
    { offsets: WEEK_OFFSETS_ELEC.sub3, rowMap: TUTUGA_ELEC3_ROW_W1 }
  ];

  for (var w = 1; w <= 5; w++) {
    var weekDays = (allData.electrical && allData.electrical[w]) || null;
    if (!weekDays) continue;
    DAYS5.forEach(function(dc) {
      var dayData = weekDays[dc];
      if (!dayData || typeof dayData !== 'object') return;
      var col = ELEC_DAY_COL[dc];
      // 1 つの per-day JSON に sub1/sub2/sub3 のキーが混在しているため、
      // 全 sub の rowMap を試して該当キーがあれば書き込む
      subMaps.forEach(function(s) {
        var weekOffset = s.offsets[w - 1];
        Object.keys(s.rowMap).forEach(function(key) {
          if (!Object.prototype.hasOwnProperty.call(dayData, key)) return;
          var row = s.rowMap[key] + weekOffset;
          _tutugaWriteCell(ws, row, col, dayData[key]);
        });
      });
    });
  }
}

// 日常機械設備シート (sub1/2/3 を 1 シートに 5 週分書き込み, 共通ピッチ 177)
function _tutugaWriteMechanicalSheet(ws, allData) {
  var WEEK_OFFSETS_MECH = _tutugaConst('WEEK_OFFSETS_MECH', [0, 177, 354, 531, 707]);
  var MECH_DAY_COL = _tutugaConst('MECH_DAY_COL', { mon:5, tue:6, wed:7, thu:8, fri:9 });
  var DAYS5 = ['mon','tue','wed','thu','fri'];
  var rowMaps = [TUTUGA_MECH1_ROW_W1, TUTUGA_MECH2_ROW_W1, TUTUGA_MECH3_ROW_W1];

  for (var w = 1; w <= 5; w++) {
    var weekDays = (allData.mechanical && allData.mechanical[w]) || null;
    if (!weekDays) continue;
    var weekOffset = WEEK_OFFSETS_MECH[w - 1];
    DAYS5.forEach(function(dc) {
      var dayData = weekDays[dc];
      if (!dayData || typeof dayData !== 'object') return;
      var col = MECH_DAY_COL[dc];
      rowMaps.forEach(function(rowMap) {
        Object.keys(rowMap).forEach(function(key) {
          if (!Object.prototype.hasOwnProperty.call(dayData, key)) return;
          var row = rowMap[key] + weekOffset;
          _tutugaWriteCell(ws, row, col, dayData[key]);
        });
      });
    });
  }
}

// =====================================================================
// 公開 API: buildTutugaWorkbook(allData) → Promise<ExcelJS.Workbook>
// =====================================================================
async function buildTutugaWorkbook(allData) {
  if (typeof ExcelJS === 'undefined') {
    throw new Error('ExcelJS が読み込まれていません。先に exceljs.min.js をロードしてください');
  }
  if (typeof EXCEL_TEMPLATE_B64 === 'undefined' || !EXCEL_TEMPLATE_B64) {
    throw new Error('筒賀 Excel テンプレート (EXCEL_TEMPLATE_B64) が読み込まれていません');
  }
  var bytes = Uint8Array.from(atob(EXCEL_TEMPLATE_B64), function(c) { return c.charCodeAt(0); });
  var wb = new ExcelJS.Workbook();
  await wb.xlsx.load(bytes.buffer);

  var data = allData || {};
  var wsWater = wb.worksheets[TUTUGA_SHEET_IDX.daily_water];
  var wsEquip = wb.worksheets[TUTUGA_SHEET_IDX.equipment_hours];
  var wsElec  = wb.worksheets[TUTUGA_SHEET_IDX.daily_elec];
  var wsMech  = wb.worksheets[TUTUGA_SHEET_IDX.daily_mech];

  if (wsWater) _tutugaWriteWaterSheet(wsWater, data);
  if (wsEquip) _tutugaWriteEquipmentSheet(wsEquip, data);
  if (wsElec)  _tutugaWriteElectricalSheet(wsElec, data);
  if (wsMech)  _tutugaWriteMechanicalSheet(wsMech, data);

  // 運転管理月報 / 水質管理報告 は Phase 5+ で実装予定
  return wb;
}

// グローバル公開 (ブラウザ)
if (typeof window !== 'undefined') {
  window.buildTutugaWorkbook = buildTutugaWorkbook;
  window.TUTUGA_SHEET_IDX = TUTUGA_SHEET_IDX;
  window.TUTUGA_USAGE_ROW_OFFSET = TUTUGA_USAGE_ROW_OFFSET;
  window.TUTUGA_MEASURE_ROW_OFFSET = TUTUGA_MEASURE_ROW_OFFSET;
  window.TUTUGA_EQUIP_KEYS_ORDERED = TUTUGA_EQUIP_KEYS_ORDERED;
  window.TUTUGA_ELEC1_ROW_W1 = TUTUGA_ELEC1_ROW_W1;
  window.TUTUGA_ELEC2_ROW_W1 = TUTUGA_ELEC2_ROW_W1;
  window.TUTUGA_ELEC3_ROW_W1 = TUTUGA_ELEC3_ROW_W1;
  window.TUTUGA_MECH1_ROW_W1 = TUTUGA_MECH1_ROW_W1;
  window.TUTUGA_MECH2_ROW_W1 = TUTUGA_MECH2_ROW_W1;
  window.TUTUGA_MECH3_ROW_W1 = TUTUGA_MECH3_ROW_W1;
}
